// loadOrderWithTenantScope loads an order scoped to a specific tenant.
// SECURE: The query includes tenant_id in the WHERE clause, ensuring tenant isolation
// at the database query level. We never fetch by ID alone.
func (h *OrderHandler) loadOrderWithTenantScope(ctx context.Context, orderID, tenantID string) (*Order, error) {
	query := `
		SELECT id, user_id, tenant_id, status, total_amount, items, created_at, updated_at
		FROM orders
		WHERE id = $1 AND tenant_id = $2
	`

	order := &Order{}
	err := h.DB.QueryRowContext(ctx, query, orderID, tenantID).Scan(
		&order.ID,
		&order.UserID,
		&order.TenantID,
		&order.Status,
		&order.TotalAmount,
		&order.Items,
		&order.CreatedAt,
		&order.UpdatedAt,
	)
	if err != nil {
		return nil, err
	}

	return order, nil
}

